SELECT SUM(Consumption) as TotalConsumptionKAM
FROM yearmonth
WHERE CustomerID IN (
    SELECT CustomerID FROM customers WHERE Segment = 'KAM'
) AND Date LIKE '2013%';


4. Calculate the annual average consumption for SME customers in CZK for the year 2013:


SELECT AVG(TotalConsumptionSME) as AvgConsumptionSME
FROM (
    SELECT SUM(Consumption) as TotalConsumptionSME
    FROM yearmonth
    WHERE CustomerID IN (
        SELECT CustomerID FROM customers WHERE Segment = 'SME'
    ) AND Date LIKE '2013%'
